import * as fs from 'fs';
import * as path from 'path';
import { validate } from './validator';
import { mergeDefaults } from '../utils/merge';
import type { AppConfig } from './types';

export function loadConfig(filePath: string): AppConfig {
  const ext = path.extname(filePath);
  if (ext !== '.json') {
    throw new Error(`Unsupported config format: ${ext}`);
  }

  const raw = fs.readFileSync(filePath, 'utf-8');
  const parsed = JSON.parse(raw);
  const validated = validate(parsed);
  return mergeDefaults(validated);
}

import type { AppConfig } from './types';

export function validate(config: unknown): Partial<AppConfig> {
  if (typeof config !== 'object' || config === null) {
    throw new Error('Config must be an object');
  }
  const obj = config as Record<string, unknown>;
  if (obj.port !== undefined && typeof obj.port !== 'number') {
    throw new Error('port must be a number');
  }
  if (obj.host !== undefined && typeof obj.host !== 'string') {
    throw new Error('host must be a string');
  }
  return obj as Partial<AppConfig>;
}

export interface AppConfig {
  host: string;
  port: number;
  database: {
    url: string;
    pool: number;
  };
  logging: {
    level: 'debug' | 'info' | 'warn' | 'error';
    file?: string;
  };
}

import type { AppConfig } from '../config/types';

const DEFAULTS: AppConfig = {
  host: 'localhost',
  port: 3000,
  database: { url: 'postgresql://localhost:5432/app', pool: 5 },
  logging: { level: 'info' },
};

export function mergeDefaults(partial: Partial<AppConfig>): AppConfig {
  return {
    ...DEFAULTS,
    ...partial,
    database: { ...DEFAULTS.database, ...(partial.database || {}) },
    logging: { ...DEFAULTS.logging, ...(partial.logging || {}) },
  };
}

import * as fs from 'fs';
import * as path from 'path';

export function readTextFile(filePath: string): string {
  return fs.readFileSync(path.resolve(filePath), 'utf-8');
}

export function fileExists(filePath: string): boolean {
  return fs.existsSync(path.resolve(filePath));
}

export function getExtension(filePath: string): string {
  return path.extname(filePath).toLowerCase();
}
